// Composant racine — définit les routes de l'application
import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import Landing from './app/Landing';
import Login from './app/Login';
import Register from './app/Register';
import Chat from './app/Chat';

// Route protégée : redirige vers /login si non connecté
function PrivateRoute({ children }) {
  const { user, loading } = useAuth();
  if (loading) return <div style={{ display:'flex',alignItems:'center',justifyContent:'center',height:'100vh',color:'#9a9aaa' }}>Chargement...</div>;
  return user ? children : <Navigate to="/login" replace />;
}

function AppRoutes() {
  return (
    <Routes>
      {/* Page d'accueil publique */}
      <Route path="/" element={<Landing />} />

      {/* Pages d'authentification */}
      <Route path="/login" element={<Login />} />
      <Route path="/register" element={<Register />} />

      {/* Page chat — protégée, login requis */}
      <Route path="/chat" element={
        <PrivateRoute><Chat /></PrivateRoute>
      } />

      {/* Redirection par défaut */}
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  );
}

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <AppRoutes />
      </BrowserRouter>
    </AuthProvider>
  );
}
